private struct AppleTVHomeScreen: View {
    var body: some View {
        NavigationStack {
            ZStack(alignment: .bottom) {
                ScrollView {
                    VStack(alignment: .leading, spacing: 20) {
                        AppleTVHeroBillboard()
                        ForEach(AppleTVDemoData.rows) { row in
                            AppleTVPosterRow(title: row.title, items: row.items, accent: AppleTVTokens.atvTextPrimary)
                        }
                    }
                    .padding(.bottom, 24)
                }
                .background(AppleTVTokens.atvCanvas.ignoresSafeArea())
            }
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .principal) { Text("Apple TV").font(.system(size: 20, weight: .bold)).foregroundStyle(AppleTVTokens.atvTextPrimary) }
                ToolbarItem(placement: .topBarTrailing) { Image(systemName: "person.crop.circle").foregroundStyle(AppleTVTokens.atvTextPrimary) }
            }
            .toolbarBackground(AppleTVTokens.atvCanvas, for: .navigationBar)
        }
    }
}

